            '@keyframes fmxFire{0%,100%{opacity:.7;transform:scaleY(1);}20%{opacity:.95;transform:scaleY(1.05);}40%{opacity:.72;}55%{opacity:1;transform:scaleY(1.04);}70%{opacity:.8;}85%{opacity:.95;}}',
